package ir.tahamohamadi.content.featured; import ir.tahamohamadi.blog.post.BlogPost; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.portfolio.project.PortfolioProject; import ir.tahamohamadi.publication.Publication; import jakarta.persistence.*; import lombok.*; import java.time.Instant;
@Entity @Table(name="featured_item") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class FeaturedItem extends AuditedSoftDeletableEntity { @Column(name="slot_key",nullable=false) private String slotKey; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="blog_post_id") private BlogPost blogPost; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="portfolio_project_id") private PortfolioProject portfolioProject; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="publication_id") private Publication publication; @Column(name="sort_order",nullable=false) private int sortOrder; @Column(name="starts_at") private Instant startsAt; @Column(name="ends_at") private Instant endsAt; @Column(name="is_active",nullable=false) private boolean active; }
